1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	type QuoteResult = { premium: number };
10	type ClaimResult = { payout: number; remainingCap: number };
11	type StepResult = QuoteResult | ClaimResult;
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	
16	const ITEM_BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const ITEM_INSURANCE_VALUES: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const BLOCK_SIZE = 3;
35	const BLOCK_BASE_PREMIUM = 60;
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	const CURSE_RATE = 0.5;
39	const HIGH_ENCHANTMENT_RATE = 0.3;
40	const HIGH_ENCHANTMENT_THRESHOLD = 5;
41	const LOYALTY_RATE = 0.2;
42	const LOYALTY_THRESHOLD_YEARS = 2;
43	const FOLLOW_UP_RATE = 0.15;
44	
45	const CAP_MULTIPLIER = 2;
46	const DEDUCTIBLE = 100;
47	
48	const sumBy = <T>(items: T[], f: (x: T) => number): number =>
49	  items.reduce((acc, x) => acc + f(x), 0);
50	
51	const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];
52	
53	const SURCHARGE_RULES: ReadonlyArray<{ applies: (item: Item) => boolean; rate: number }> = [
54	  { applies: (item) => item.cursed === true, rate: CURSE_RATE },
55	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_RATE },
56	];
57	
58	const surchargeFor = (item: Item): number => {
59	  const base = baseFor(item);
60	  return sumBy(SURCHARGE_RULES, (rule) => (rule.applies(item) ? base * rule.rate : 0));
61	};
62	
63	const totalSurchargeFor = (items: Item[]): number => sumBy(items, surchargeFor);
64	
65	type QuoteContext = { customer: Customer; isFollowUp: boolean };
66	
67	const DISCOUNT_RULES: ReadonlyArray<{ applies: (ctx: QuoteContext) => boolean; rate: number }> = [
68	  { applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, rate: LOYALTY_RATE },
69	  { applies: (ctx) => ctx.isFollowUp, rate: FOLLOW_UP_RATE },
70	];
71	
72	const totalDiscountFor = (ctx: QuoteContext, totalBase: number): number =>
73	  sumBy(DISCOUNT_RULES, (rule) => (rule.applies(ctx) ? totalBase * rule.rate : 0));
74	
75	const premiumFor = (totalBase: number, totalSurcharge: number, ctx: QuoteContext): number =>
76	  Math.ceil(
77	    totalBase
78	    + totalSurcharge
79	    + totalBase * FIRST_INSURANCE_RATE
80	    - totalDiscountFor(ctx, totalBase)
81	    + PROCESSING_FEE,
82	  );
83	
84	const groupsByType = (items: Item[]): Item[][] => {
85	  const types = new Set(items.map((item) => item.type));
86	  return Array.from(types, (type) => items.filter((item) => item.type === type));
87	};
88	
89	const formsCompleteBlock = (group: Item[]): boolean =>
90	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(group[0].type);
91	
92	const baseForGroup = (group: Item[]): number =>
93	  formsCompleteBlock(group) ? BLOCK_BASE_PREMIUM : sumBy(group, baseFor);
94	
95	const totalBaseFor = (items: Item[]): number =>
96	  sumBy(groupsByType(items), baseForGroup);
97	
98	const insuranceSumFor = (items: Item[]): number =>
99	  sumBy(items, (item) => ITEM_INSURANCE_VALUES[item.type]);
100	
101	type Policy = { items: Item[]; remainingCap: number };
102	
103	const newPolicy = (items: Item[]): Policy => ({
104	  items,
105	  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
106	});
107	
108	const payoutForDamage = (damage: Damage): number =>
109	  Math.max(0, damage.amount - DEDUCTIBLE);
110	
111	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
112	  const grossPayout = sumBy(incident.damages, payoutForDamage);
113	  const payout = Math.min(grossPayout, policy.remainingCap);
114	  policy.remainingCap -= payout;
115	  return { payout, remainingCap: policy.remainingCap };
116	};
117	
118	const quoteFor = ({ items }: QuoteStep, ctx: QuoteContext): QuoteResult => ({
119	  premium: premiumFor(totalBaseFor(items), totalSurchargeFor(items), ctx),
120	});
121	
122	export const processScenario = (input: Scenario): { results: StepResult[] } => {
123	  const policies: Policy[] = [];
124	  let quoteCount = 0;
125	  const results: StepResult[] = input.steps.map((step) => {
126	    if (step.op === "quote") {
127	      const ctx: QuoteContext = { customer: input.customer, isFollowUp: quoteCount > 0 };
128	      quoteCount += 1;
129	      policies.push(newPolicy(step.items));
130	      return quoteFor(step, ctx);
131	    }
132	    return processClaim(policies[step.policy], step.incident);
133	  });
134	  return { results };
135	};
